{"code": "import json

# Load data
data_key = 'query_db_18'
if data_key in locals():
    data = locals()[data_key]
else:
    # Try reading from storage path
    data = []

# Count transfers per agent
transfer_counts = {}
case_counts = {}

print(f"Number of records: {len(data)}")

# Process each record
for record in data:
    old_agent = record['oldvalue__c']
    new_agent = record['newvalue__c']

    # Count cases handled by agent (receiving the case)
    if new_agent != 'None':
        case_counts[new_agent] = case_counts.get(new_agent, 0) + 1

    # Count transfers FROM agent (old agent)
    if old_agent != 'None':
        transfer_counts[old_agent] = transfer_counts.get(old_agent, 0) + 1

print(f"Total agents who handled cases: {len(case_counts)}")

# Find agents with > 0 cases who also have transfer data
eligible = {}
for agent in case_counts:
    if case_counts[agent] > 0:
        eligible[agent] = transfer_counts.get(agent, 0)

print(f"Eligible agents (>0 cases): {len(eligible)}")

# Find agent with minimum transfers
if eligible:
    # Sort by transfer count and then by agent ID for tie-breaking
    sorted_agents = sorted(eligible.items(), key=lambda x: (x[1], x[0]))
    min_agent = sorted_agents[0][0]
    min_transfers = sorted_agents[0][1]
    print(f"Agent with fewest transfers: {min_agent} ({min_transfers} transfers)")
    result = min_agent
else:
    result = "None found"
    print("No eligible agents found")

# Output according to required format
print("__RESULT__:")
print(json.dumps(result))"}

